mkdir -p /tmp/stackalloc-test && cd /tmp/stackalloc-test && dotnet new console --force -o . --no-restore -n StackallocTest >/dev/null 2>&1 && cat <<'EOF' > Program.cs
using System;

unsafe
{
    Span<nint> span = stackalloc nint[4];
    span[0] = 10;
    span[1] = 20;
    span[2] = 30;
    span[3] = 40;

    Console.WriteLine($"nint size: {sizeof(nint)} bytes");
    for (int i = 0; i < span.Length; i++)
        Console.WriteLine($"span[{i}] = {span[i]}");

    Span<nuint> uspan = stackalloc nuint[3];
    uspan[0] = 100;
    uspan[1] = 200;
    uspan[2] = 300;

    Console.WriteLine($"\nnuint size: {sizeof(nuint)} bytes");
    for (int i = 0; i < uspan.Length; i++)
        Console.WriteLine($"uspan[{i}] = {uspan[i]}");
}
EOF
cat <<'EOF' > StackallocTest.csproj
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
    <AllowUnsafeBlocks>true</AllowUnsafeBlocks>
  </PropertyGroup>
</Project>
EOF
dotnet run 2>&1

